// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract AuditLog {
    event EventLogged(
        string eventType,
        address indexed from,
        address indexed to,
        string description,
        uint256 timestamp
    );

    function logEvent(string memory _eventType, address _to, string memory _description) external {
        emit EventLogged(_eventType, msg.sender, _to, _description, block.timestamp);
    }
}
